import React, { useEffect, useState } from 'react';
import './Header.css';

const Header: React.FC = () => {
  const [showStars, setShowStars] = useState(false);
  const [showText, setShowText] = useState(false);
  const [showAvatar, setShowAvatar] = useState(false);
  const [showCopyright, setShowCopyright] = useState(false);
  const [showLagentry, setShowLagentry] = useState(false);

  useEffect(() => {
    // Animation sequence timing
    const timeline = [
      { delay: 500, action: () => setShowStars(true) },
      { delay: 1500, action: () => setShowText(true) },
      { delay: 3000, action: () => setShowAvatar(true) },
      { delay: 4000, action: () => setShowCopyright(true) },
      { delay: 5000, action: () => setShowLagentry(true) }
    ];

    timeline.forEach(({ delay, action }) => {
      setTimeout(action, delay);
    });
  }, []);

  // Create particle effect
  useEffect(() => {
    const createParticles = () => {
      const particlesContainer = document.getElementById('stars-container');
      if (!particlesContainer) return;

      // Clear existing particles
      particlesContainer.innerHTML = '';

      for (let i = 0; i < 80; i++) {
        const particle = document.createElement('div');
        particle.className = 'star';
        particle.style.left = Math.random() * 100 + '%';
        particle.style.top = Math.random() * 100 + '%';
        particle.style.animationDelay = Math.random() * 20 + 's';
        particle.style.animationDuration = (Math.random() * 10 + 10) + 's';
        
        // Add variety to star sizes
        const size = Math.random() * 2 + 1; // 1px to 3px
        particle.style.width = size + 'px';
        particle.style.height = size + 'px';
        
        // Add variety to star brightness - pure white stars
        const brightness = Math.random() * 0.6 + 0.4; // 0.4 to 1.0 opacity for white stars
        particle.style.opacity = brightness.toString();
        
        particlesContainer.appendChild(particle);
      }
    };

    if (showStars) {
      createParticles();
    }
  }, [showStars]);

  return (
    <header className="header">
      <div className="header-background">
        <div className="stars"></div>
        <div className="stars2"></div>
        <div className="stars3"></div>
        
        {/* New Stars Container */}
        <div id="stars-container" className={`stars-container ${showStars ? 'visible' : ''}`}></div>
        
        {/* Sliding Text */}
        <div className={`sliding-text ${showText ? 'visible' : ''}`}>
          <h2>There's a new Web Dev in town</h2>
        </div>
        
        {/* Avatar */}
        <div className={`avatar-container ${showAvatar ? 'visible' : ''}`}>
          <div className="avatar">
            <div className="avatar-face"></div>
            <div className="avatar-body"></div>
          </div>
        </div>
        
        {/* Copyright */}
        <div className={`copyright-text ${showCopyright ? 'visible' : ''}`}>
          <p>© 2024 Lagentry. All rights reserved.</p>
        </div>
        
        {/* Lagentry Text */}
        <div className={`lagentry-text ${showLagentry ? 'visible' : ''}`}>
          <h2>Lagentry</h2>
          <p>Your AI Agent Creation Platform</p>
        </div>
      </div>
      
      <div className="header-content">
        <h1 className="logo-text">Lagentry</h1>
      </div>
    </header>
  );
};

export default Header;
